// ── 1. Records ────────────────────────────────────────────────
record Point(int x, int y) {}
record Circle(Point center, double radius) implements Shape {}
record Rect(Point topLeft, int width, int height) implements Shape {}

// Compact canonical constructor (validation)
record Range(int lo, int hi) {
    Range {  // compact constructor — same as Range(int lo, int hi)
        if (lo > hi) throw new IllegalArgumentException(lo + " > " + hi);
    }
}

// ── 2. Sealed Classes ──────────────────────────────────────────
sealed interface Shape permits Circle, Rect, Triangle {}
record Triangle(Point a, Point b, Point c) implements Shape {}

// ── 3. Pattern Matching ────────────────────────────────────────
public class Demo {
    // instanceof pattern (Java 16+)
    static void printIfString(Object obj) {
        if (obj instanceof String s && s.length() > 3) {
            System.out.println("Long string: " + s.toUpperCase());
        }
    }

    // Switch pattern (Java 21 GA) — exhaustive over sealed hierarchy
    static double area(Shape shape) {
        return switch (shape) {
            case Circle  c -> Math.PI * c.radius() * c.radius();
            case Rect    r -> (double) r.width() * r.height();
            case Triangle t -> {
                // Heron's formula approximation
                double ab = dist(t.a(), t.b());
                double bc = dist(t.b(), t.c());
                double ca = dist(t.c(), t.a());
                double s  = (ab + bc + ca) / 2;
                yield Math.sqrt(s * (s-ab) * (s-bc) * (s-ca));
            }
        }; // NO default needed — sealed hierarchy is exhaustive
    }

    static double dist(Point p, Point q) {
        return Math.hypot(p.x()-q.x(), p.y()-q.y());
    }

    public static void main(String[] args) {
        var c  = new Circle(new Point(0,0), 5);
        var r  = new Rect(new Point(1,1), 4, 3);

        System.out.println(c);              // Circle[center=Point[x=0, y=0], radius=5.0]
        System.out.println(c.center());     // Point[x=0, y=0]
        System.out.printf("Circle area: %.2f%n", area(c));  // 78.54
        System.out.printf("Rect area:   %.2f%n", area(r));  // 12.00

        // Records have value-based equality
        System.out.println(new Point(1,2).equals(new Point(1,2))); // true

        printIfString("Hello World"); // Long string: HELLO WORLD
        printIfString(42);            // (no output)

        try { new Range(5, 1); } catch (IllegalArgumentException e) { System.out.println(e.getMessage()); }
    }
}

