import java.util.*;

public class Q1 {
    sealed interface Shape permits Circle, Rect, Triangle {}
    record Circle(double r) implements Shape {}
    record Rect(double w, double h) implements Shape {}
    record Triangle(double base, double height) implements Shape {}

    static Shape parse(String line) {
        String[] p = line.split(":");
        return switch (p[0]) {
            case "CIRCLE"   -> new Circle(Double.parseDouble(p[1]));
            case "RECT"     -> new Rect(Double.parseDouble(p[1]), Double.parseDouble(p[2]));
            case "TRIANGLE" -> new Triangle(Double.parseDouble(p[1]), Double.parseDouble(p[2]));
            default -> throw new IllegalArgumentException(p[0]);
        };
    }

    static double area(Shape shape) {
        return switch (shape) {
            case Circle   c -> Math.PI * c.r() * c.r();
            case Rect     r -> r.w() * r.h();
            case Triangle t -> 0.5 * t.base() * t.height();
        };
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        double total = 0;
        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (!line.isEmpty()) total += area(parse(line));
        }
        System.out.printf("%.2f%n", total);
    }
}

