import java.util.*;

public class Q2 {
    record DateRange(int startYear, int endYear) {
        DateRange {
            if (startYear > endYear) throw new IllegalArgumentException("startYear > endYear");
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (line.isEmpty()) continue;
            String[] p = line.split(" ");
            int s = Integer.parseInt(p[0]), e = Integer.parseInt(p[1]);
            try {
                DateRange dr = new DateRange(s, e);
                System.out.println("OK: " + dr.startYear() + "-" + dr.endYear());
            } catch (IllegalArgumentException ex) {
                System.out.println("ERR: " + ex.getMessage());
            }
        }
    }
}

