import java.util.*;

public class Q3 {
    sealed interface JsonNode permits JsonNull, JsonBool, JsonNum, JsonStr {}
    record JsonNull() implements JsonNode {}
    record JsonBool(boolean v) implements JsonNode {}
    record JsonNum(double v) implements JsonNode {}
    record JsonStr(String v) implements JsonNode {}

    static JsonNode parse(String line) {
        if (line.equals("NULL")) return new JsonNull();
        String[] p = line.split(":", 2);
        return switch (p[0]) {
            case "BOOL" -> new JsonBool(Boolean.parseBoolean(p[1]));
            case "NUM"  -> new JsonNum(Double.parseDouble(p[1]));
            case "STR"  -> new JsonStr(p[1]);
            default     -> throw new IllegalArgumentException(line);
        };
    }

    static String render(JsonNode node) {
        return switch (node) {
            case JsonNull  n -> "null";
            case JsonBool  b -> String.valueOf(b.v());
            case JsonNum   n -> {
                double v = n.v();
                yield (v == Math.floor(v) && !Double.isInfinite(v))
                    ? String.valueOf((long) v) : String.valueOf(v);
            }
            case JsonStr   s -> "\"" + s.v() + "\"";
        };
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLine()) {
            String line = sc.nextLine().trim();
            if (!line.isEmpty()) System.out.println(render(parse(line)));
        }
    }
}
